count = 0
for b in books:
    bid = b.get("id")
    if bid in updates:
        for i, t in enumerate(b.get("thoughts", [])):
            if i in updates[bid]:
                new_life = updates[bid][i]
                ex = t["example"]
                life_start = ex.find("\n\n**В жизни:**")
                if life_start >= 0:
                    t["example"] = ex[:life_start] + "\n\n**В жизни:** " + new_life
                    count += 1

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))
print(f"Updated {count} thoughts")
